import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "AI Threat Detection",
  subtitle: "Machine learning-powered anomaly detection using Isolation Forest algorithms",
  description: "Our advanced AI-driven threat detection system uses sophisticated machine learning algorithms to identify and respond to security threats in real-time. The Isolation Forest algorithm continuously analyzes user behavior, network traffic, and system logs to detect anomalies before they become security incidents. Our deep learning models are trained on billions of security events and continuously updated with global threat intelligence.",
  benefits: [
    "Real-time behavioral anomaly detection using advanced ML algorithms",
    "Predictive threat modeling based on global threat intelligence",
    "Autonomous incident containment with <100ms response time",
    "Continuous model training with federated learning approach",
    "Zero-day threat detection without signature updates"
  ],
  features: [
    { title: "Isolation Forest Detection", description: "Advanced algorithm that isolates anomalies by randomly selecting features and splitting values" },
    { title: "Behavioral Analysis", description: "Continuous monitoring of user and entity behavior patterns" },
    { title: "Threat Intelligence Feed", description: "Integration with global threat intelligence sources for real-time updates" },
    { title: "Auto-Response", description: "Automated containment and remediation actions based on threat severity" },
    { title: "Custom Rules Engine", description: "Define custom detection rules based on your specific security requirements" }
  ],
  howItWorks: [
    { title: "Data Collection", description: "Agents collect telemetry data from endpoints, networks, and cloud workloads" },
    { title: "Model Analysis", description: "ML models analyze patterns and identify deviations from normal behavior" },
    { title: "Threat Scoring", description: "Each anomaly is scored based on severity, context, and historical data" },
    { title: "Automated Response", description: "Threats are contained automatically based on predefined playbooks" }
  ],
  color: "#4f46e5",
  icon: "M13 10V3L4 14h7v7l9-11h-7z",
  gradient: "from-violet-600 to-indigo-600"
};

function ThreatDetection() {
  return <FeatureDetail {...pageData} />;
}

export default ThreatDetection;
